const MOD = 10**9 + 7;

/**
 * Calculates the sum of digits of a non-negative integer n.
 * @param {number} n
 * @returns {number}
 */
function calculateDigitSum(n) {
    let sum = 0;
    // Since n <= 5000, standard string conversion is fast enough.
    let s = String(n);
    for (let char of s) {
        sum += parseInt(char);
    }
    return sum;
}

/**
 * Solves the problem by using Dynamic Programming.
 * DP[i][j] stores the number of valid sequences arr[0]...arr[i] such that arr[i] = j.
 * We optimize space by only storing the previous and current DP state.
 * 
 * @param {number[]} digitSum
 * @returns {number}
 */
function solve(digitSum) {
    const N = digitSum.length;
    const MAX_VAL = 5000;

    // D_prev[j]: Number of valid prefixes ending at j in the previous step (i-1).
    // P_prev[j]: Prefix sum of D_prev up to j.
    // Size MAX_VAL + 1 (for indices 0 to 5000)
    let D_prev = new Array(MAX_VAL + 1).fill(0);
    let P_prev = new Array(MAX_VAL + 1).fill(0);

    // --- Base Case: i = 0 ---
    const S0 = digitSum[0];

    for (let j = 0; j <= MAX_VAL; j++) {
        if (calculateDigitSum(j) === S0) {
            D_prev[j] = 1;
        }
    }

    // Calculate initial prefix sums P_prev
    P_prev[0] = D_prev[0];
    for (let j = 1; j <= MAX_VAL; j++) {
        P_prev[j] = (P_prev[j - 1] + D_prev[j]) % MOD;
    }

    // --- DP Transition: i = 1 to N-1 ---
    for (let i = 1; i < N; i++) {
        const Si = digitSum[i];

        let D_curr = new Array(MAX_VAL + 1).fill(0);
        let P_curr = new Array(MAX_VAL + 1).fill(0);

        // Calculate D_curr[j] for step i
        for (let j = 0; j <= MAX_VAL; j++) {
            if (calculateDigitSum(j) === Si) {
                // DP[i][j] = Sum of DP[i-1][k] for all k <= j.
                // This is exactly P_prev[j].
                D_curr[j] = P_prev[j];
            }
        }

        // Calculate P_curr (Prefix sums of D_curr)
        P_curr[0] = D_curr[0];
        for (let j = 1; j <= MAX_VAL; j++) {
            P_curr[j] = (P_curr[j - 1] + D_curr[j]) % MOD;
        }

        // Update states for the next iteration
        D_prev = D_curr;
        P_prev = P_curr;
    }

    // The final answer is the sum of all counts in the last DP row, which is P_prev[MAX_VAL].
    return P_prev[MAX_VAL];
}

